  ('heelevel3-7ec62a85-moex-00176', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '下列何者非訴願審理機關審理訴願案件應遵循之原則？', '["書面審查原則", "職權調查原則", "不利益變更禁止原則", "停止執行原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00177', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '軍校生甲，因行為失當，遭學校開除學籍。學校擬對甲求償已領取之公費，應循何種方式？', '["以行政處分令甲賠償", "直接依強制執行法聲請強制執行", "向行政法院提起一般給付之訴", "向民事法院提起訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00178', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '多數當事人關於訴訟標的之權利義務關係，在事實上或法律上有同一或同類原因時，有關訴訟程 序之敘述，下列何者錯誤？', '["可以成立共同訴訟，一同擔任原告或被告", "如果當事人分別起訴，法院得命其合併辯論及合併裁判", "共同訴訟之訴訟標的有合一確定必要時，共同訴訟人中一人不利於全體之行為，效力不及於全 體共同訴訟人", "共同訴訟之訴訟標的無論有無合一確定必要，當事人合意停止訴訟後，續行訴訟必須經全體同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00179', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '依行政訴訟法規定之都市計畫審查程序，行政法院審查認定都市計畫違法時，下列何者非判決主 文得宣告之內容？', '["都市計畫違法者，宣告無效或違法", "都市計畫發布後始發生違法原因者，應宣告自違法原因發生時起失效", "同一都市計畫中未經原告請求，而與原告請求宣告無效之部分具不可分關係，經法院審查認定 違法者，併宣告撤銷", "依法僅得為違法之宣告者，應宣告其違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00180', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '某市政府自行興建設置之公立醫院委託私立醫學院經營，因原先所設置之手扶梯未定期保養而故 障，導致病患摔傷。下列敘述何者正確？', '["公共設施委託私人管理，因管理欠缺致人民身體受損害者，負國家賠償責任", "私立醫學院與病患間雖係私法關係，仍不得依民法向醫院求償", "委託屬公法關係，故病患不得依民法向醫院求償", "如病患為外國人者，則無法依國家賠償法求償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00181', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-112-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '下列何者非屬政府應給予損失補償之適例？', '["公務員死亡後，所屬機關收回配住之宿舍", "警察依法追捕逃犯，遭逃犯衝撞警車，不慎導致路人甲受重傷", "消防隊為進入火場救火，移除窄巷內之機車，致機車受損", "主管機關就都市計畫道路用地，在徵收之前埋設地下公用管線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00182', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-8d1d3a67', 'sub-heelevel3-7ec62a85-04', NULL, 'essay', '甲因涉嫌販毒遭警方依法監聽。過程中，聽到有人打電話給甲說「要珍
奶兩杯」，甲回答「好，老地方見」，這些談話均被錄下。偵查終結後甲
遭檢察官起訴，審判中有證人證稱「珍奶」實即毒品之代稱，甲則主張
上述之談話內容不可做為證據。問甲之主張有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "6d26b77798a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "1113", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00183', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-8d1d3a67', 'sub-heelevel3-7ec62a85-04', NULL, 'essay', '甲因犯罪遭檢察官起訴。審判期日時，甲經合法傳喚，無正當理由不到
庭，但證人乙已到庭，法院遂改行準備程序，於乙具結後，由檢察官及
甲之辯護人進行交互詰問。試問證人乙之陳述是否有證據能力？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "6d26b77798a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "1113", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00184', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-8d1d3a67', 'sub-heelevel3-7ec62a85-04', NULL, 'essay', '甲因酒駕遭查獲，冒用乙之身分證應訊。後檢察官以該身分證所載之姓
名、性別、年齡、住所等資料聲請簡易判決處刑。第一審簡易判決判決
乙有罪，檢察官發現有誤後，聲請法院將乙改成甲。問法院該如何處理？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:21+00:00", "source_pdf_sha1": "6d26b77798a0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "1113", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00185', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-111-8d1d3a67', 'sub-heelevel3-7ec62a85-04', NULL, 'essay', '甲持槍至超商行搶後逃逸。警員乙到超商瞭解案情，觀看監視錄影器畫
面後，乙確認為就是前科累累的甲犯案。三天後，乙在巡邏時發現甲，
乙遂立即逮捕甲，甲立即供稱槍是丙借他的，行搶後已經還給丙。乙根
據此線索向法官聲請到搜索票後，持票搜索丙之住宅，果然找到該把手
槍。甲後於審判中主張警員乙的作為均屬違法，取得之手槍不得做為證
